// Aggregate GitHub activity for Claude
const commits = Array.isArray($input.all()[0]?.json) ? $input.all()[0].json : [];
const issues = Array.isArray($input.all()[1]?.json) ? $input.all()[1].json : [];
const prs = Array.isArray($input.all()[2]?.json) ? $input.all()[2].json.filter(p => p.merged_at) : [];

const lastWeek = new Date(); lastWeek.setDate(lastWeek.getDate() - 7);
const recentCommits = commits.filter(c => new Date(c.commit.author.date) >= lastWeek);
const recentIssues = issues.filter(i => i.closed_at && new Date(i.closed_at) >= lastWeek);

const topAuthors = {};
recentCommits.forEach(c => { const a = c.commit?.author?.name || 'unknown'; topAuthors[a] = (topAuthors[a]||0)+1; });
const topContributors = Object.entries(topAuthors).sort((a,b) => b[1]-a[1]).slice(0,5);

const prompt = `You are a senior developer relations writer. Write a concise weekly narrative summary.

Repo: ${$env.REPO}
Period: ${lastWeek.toISOString().split('T')[0]} → ${new Date().toISOString().split('T')[0]}

Stats: ${recentCommits.length} commits, ${recentIssues.length} closed issues, ${prs.length} PRs merged.
Top contributors: ${topContributors.map(([n,c])=>`${n} (${c} commits)`).join(', ')}

Recent commits:\n${recentCommits.slice(0,8).map(c=>`- ${c.sha?.slice(0,7)} ${c.commit?.message?.split('\n')[0]}`).join('\n')}

Closed issues:\n${recentIssues.slice(0,5).map(i=>`- #${i.number} ${i.title}`).join('\n')}

Merged PRs:\n${prs.slice(0,5).map(p=>`- #${p.number} ${p.title} by @${p.user?.login}`).join('\n')}

Format in ${$env.LANGUAGE || 'EN'} as:
## 📊 Weekly Dev Summary — ${$env.REPO}
**Period: ${lastWeek.toISOString().split('T')[0]} → ${new Date().toISOString().split('T')[0]}**

### 🎯 Highlights
[3-4 sentence narrative of most interesting activity]

### 📈 Stats
- Commits: ${recentCommits.length}
- Issues Closed: ${recentIssues.length}
- PRs Merged: ${prs.length}

### 👥 Top Contributors
${topContributors.map(([n,c])=>`- @${n}: ${c} commits`).join('\n')}

### 🔥 Shipped
${prs.slice(0,3).map(p=>`- #${p.number} ${p.title}`).join('\n')}

### 💭 Community Pulse
[1-2 sentences on overall project health]

Be concise, professional, and slightly playful. Use emoji.`;

return [{ json: { prompt, commits: recentCommits, issues: recentIssues, prs, topContributors } }];

// Route to email or Discord based on config
const summary = $input.first().json.content?.[0]?.text || 'Error: no response';
const env = Object.keys(process.env).filter(k => k.startsWith('N8N_VAR_'));
const delivery = process.env.N8N_VAR_DELIVERY_METHOD || 'discord';
const repo = process.env.N8N_VAR_REPO || 'unknown';

return [{ json: { summary, delivery, repo, generatedAt: new Date().toISOString() } }];
